sql:
SELECT ip.plan_type, COUNT(DISTINCT ip.provider_id) AS provider_count
FROM insurance_plans ip
GROUP BY ip.plan_type;

SELECT provider_name 
FROM insurance_providers 
WHERE provider_id = 1;

external_knowledge:
- Individuals: refers to the patients;
- Healthcare providers: refers to the providers where claims are made;
- Insurance providers: refer to the companies providing the insurance plans;
- Plan details: include the plan name, type, premium, deductible, copay, and coinsurance;
- Claims: include claim ID, date, and amount.

sql:
SELECT DISTINCT patient_id
FROM patient_coverage
WHERE coverage_limit > 10000;

SELECT claim_id, claim_amount
FROM claims
ORDER BY claim_amount DESC;

SELECT COUNT(DISTINCT pc.patient_id) 
FROM claims c
INNER JOIN patient_coverage pc ON c.coverage_id = pc.coverage_id;
